int main() {
    BooleanFlag flag(true);
    bool res = !flag;
    std::cout << res;
    std::cout << flag.getValue();
    std::cout << "\n";

    BooleanFlag flag2(false);
    res = !flag2;
    std::cout << res;
    std::cout << flag2.getValue();
    std::cout << "\n";

    BooleanFlag flag3(true);
    !flag3; // Invert to false
    !flag3; // Invert back to true
    std::cout << flag3.getValue();
    std::cout << "\n";
    return 0;
}
